        if (o2.biff == 8 && (wb.Props || wb.Custprops)) write_xls_props(wb, cfb);
        if (o2.biff == 8 && wb.vbaraw) fill_vba_xls(cfb, CFB.read(wb.vbaraw, { type: typeof wb.vbaraw == "string" ? "binary" : "buffer" }));
        return cfb;
