var __dirname = path.dirname(fileURLToPath(import.meta.url));
var dataDir = process.env.NODE_ENV === "production" ? "/tmp/data" : path.join(__dirname, "..", "data");
if (!fs.existsSync(dataDir)) fs.mkdirSync(dataDir, { recursive: true });
var dbPath = path.join(dataDir, "analysis.db");
var BetterSqlite3Compat = class {
  sqlDb;
  dirty = false;
  saveTimer = null;
  async init() {
    const SQL = await initSqlJs();
    if (fs.existsSync(dbPath)) {
      const buf = fs.readFileSync(dbPath);
      this.sqlDb = new SQL.Database(buf);
    } else {
      this.sqlDb = new SQL.Database();
    }
    this.sqlDb.run("PRAGMA journal_mode = WAL");
    this.sqlDb.run("PRAGMA foreign_keys = ON");
  }
  save() {
    if (this.saveTimer) return;
    this.saveTimer = setTimeout(() => {
      try {
        const data = this.sqlDb.export();
        fs.writeFileSync(dbPath, Buffer.from(data));
      } catch {
      }
      this.saveTimer = null;
    }, 500);
  }
  exec(sql) {
    this.sqlDb.run(sql);
    this.save();
  }
  pragma(str2) {
    this.sqlDb.run(`PRAGMA ${str2}`);
  }
  prepare(sql) {
    const db2 = this.sqlDb;
    const self = this;
    return {
      run(...params) {
        db2.run(sql, params);
        self.save();
        return { changes: db2.getRowsModified() };
      },
      get(...params) {
        const stmt = db2.prepare(sql);
        if (params.length > 0) stmt.bind(params);
        if (stmt.step()) {
          const cols = stmt.getColumnNames();
          const vals = stmt.get();
          stmt.free();
          const row = {};
          cols.forEach((c2, i2) => {
            row[c2] = vals[i2];
          });
          return row;
        }
        stmt.free();
        return void 0;
      },
      all(...params) {
        const stmt = db2.prepare(sql);
        if (params.length > 0) stmt.bind(params);
        const rows = [];
        while (stmt.step()) {
          const cols = stmt.getColumnNames();
          const vals = stmt.get();
          const row = {};
          cols.forEach((c2, i2) => {
            row[c2] = vals[i2];
          });
          rows.push(row);
        }
        stmt.free();
        return rows;
      }
    };
  }
  transaction(fn) {
    const self = this;
    return ((...args) => {
      self.sqlDb.run("BEGIN");
      try {
        fn(...args);
        self.sqlDb.run("COMMIT");
        self.save();
      } catch (e2) {
        self.sqlDb.run("ROLLBACK");
        throw e2;
      }
    });
  }
};
