var router2 = Router2();
router2.get("/", (req, res) => {
  const limit2 = parseInt(req.query.limit) || 50;
  const offset = parseInt(req.query.offset) || 0;
  const dateFrom = req.query.date_from;
  const dateTo = req.query.date_to;
  let sql = "SELECT s.*, ss.summary_text FROM sessions s LEFT JOIN session_summaries ss ON ss.session_id = s.id WHERE 1=1";
  const params = [];
  if (dateFrom) {
    sql += " AND s.session_date >= ?";
    params.push(dateFrom);
  }
  if (dateTo) {
    sql += " AND s.session_date <= ?";
    params.push(dateTo);
  }
  sql += " ORDER BY s.sequence_num ASC LIMIT ? OFFSET ?";
  params.push(limit2, offset);
  const rows = db_default.prepare(sql).all(...params);
  const total = db_default.prepare("SELECT COUNT(*) as cnt FROM sessions").get();
  const summarized = db_default.prepare("SELECT COUNT(*) as cnt FROM session_summaries").get();
  res.json({ data: rows, total: total.cnt, summarized: summarized.cnt });
});
